// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721.sol";

contract PokemonMarketplace is ReentrancyGuard, AccessControl, Pausable {
    // ------------------------------------------------------------------------
    // Roles
    // ------------------------------------------------------------------------
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    // ------------------------------------------------------------------------
    // Structs
    // ------------------------------------------------------------------------
    struct Listing {
        address seller;
        uint256 price;
        bool active;
    }

    struct Auction {
        address seller;
        uint256 startPrice;
        uint256 reservePrice;
        uint8 minbidincrementPercentage;
        uint256 highestBid;
        address highestBidder;
        uint256 endTime;
        uint256 timeBuffer; // Snipe Protection
        bool active;
    }

    // ------------------------------------------------------------------------
    // State Variables
    // ------------------------------------------------------------------------
    IERC721 public immutable pokemonNFT;

    // tokenId → Listing
    mapping(uint256 => Listing) public listings;

    // tokenId → Auction
    mapping(uint256 => Auction) public auctions;

    // User → Pending Withdrawal Amount
    mapping(address => uint256) public pendingWithdrawals;

    // ------------------------------------------------------------------------
    // Events
    // ------------------------------------------------------------------------
    event CardListed(
        uint256 indexed tokenId,
        address indexed seller,
        uint256 price
    );

    event CardPurchased(
        uint256 indexed tokenId,
        address indexed buyer,
        uint256 price
    );

    event AuctionStarted(
        uint256 indexed tokenId,
        address indexed seller,
        uint256 startPrice,
        uint256 reservePrice,
        uint256 duration
    );

    event BidPlaced(
        uint256 indexed tokenId,
        address indexed bidder,
        uint256 amount
    );

    event AuctionExtended(
        uint256 indexed tokenId,
        address indexed bidder,
        uint256 amount,
        uint256 newEndTime
    );

    event AuctionEnded(
        uint256 indexed tokenId,
        address indexed winner,
        uint256 amount
    );

    event AuctionFailed(uint256 indexed tokenId);

    event RefundFailed(
        uint256 indexed tokenId,
        address indexed buyer,
        uint256 amount
    );

    // ------------------------------------------------------------------------
    // Constructor
    // ------------------------------------------------------------------------
    constructor(IERC721 _pokemonNFT) {
        pokemonNFT = _pokemonNFT;
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    // ------------------------------------------------------------------------
    // Modifiers
    // ------------------------------------------------------------------------
    modifier onlyAdmin() {
        require(
            hasRole(ADMIN_ROLE, msg.sender),
            "Must have ADMIN_ROLE to call this"
        );
        _;
    }

    // ------------------------------------------------------------------------
    // Pausable Functions (Emergency Controls)
    // ------------------------------------------------------------------------
    function pause() external onlyAdmin {
        _pause();
    }

    function unpause() external onlyAdmin {
        _unpause();
    }

    // ------------------------------------------------------------------------
    // Fixed-Price Listing
    // ------------------------------------------------------------------------

    /**
     * @notice List an NFT for a fixed price sale.
     * @param tokenId  The ID of the token to list.
     * @param price    Sale price in Wei = 10^-18 ETH.
     */
    function listCard(uint256 tokenId, uint256 price) external whenNotPaused {
        require(
            pokemonNFT.ownerOf(tokenId) == msg.sender,
            "Not the owner of this token"
        );
        require(price > 0, "Price must be > 0");
        // Ensure there is no active listing or auction for this token
        require(!listings[tokenId].active, "Already listed");
        require(!auctions[tokenId].active, "Token is in active auction");

        // Seller must approve Marketplace to transfer their NFT
        require(
            pokemonNFT.getApproved(tokenId) == address(this) ||
                pokemonNFT.isApprovedForAll(msg.sender, address(this)),
            "Marketplace not approved"
        );

        listings[tokenId] = Listing({
            seller: msg.sender,
            price: price,
            active: true
        });

        emit CardListed(tokenId, msg.sender, price);
    }

    /**
     * @notice Purchase a listed NFT, transferring ownership and funds.
     * @param tokenId The ID of the token being purchased.
     */
    function buyCard(
        uint256 tokenId
    ) external payable whenNotPaused nonReentrant {
        Listing storage listedItem = listings[tokenId];
        require(listedItem.active, "Token is not for sale");
        require(msg.value >= listedItem.price, "Insufficient ETH for purchase");

        // Mark listing as inactive before transferring to prevent re-entrancy
        listedItem.active = false;

        // Transfer NFT from seller to buyer
        pokemonNFT.safeTransferFrom(listedItem.seller, msg.sender, tokenId);

        // Transfer payment to the seller
        (bool sent, ) = payable(listedItem.seller).call{value: msg.value}("");
        require(sent, "Payment transfer failed");

        emit CardPurchased(tokenId, msg.sender, listedItem.price);
    }

    /**
     * @notice Cancel a listed NFT (only the seller can cancel).
     * @param tokenId The ID of the token to cancel.
     */
    function cancelListing(uint256 tokenId) external whenNotPaused {
        Listing storage listedItem = listings[tokenId];
        require(listedItem.active, "No active listing");
        require(listedItem.seller == msg.sender, "Not the seller");

        // Mark listing as inactive
        listedItem.active = false;
    }

    // ------------------------------------------------------------------------
    // Auction Mechanics
    // ------------------------------------------------------------------------

    /**
     * @notice Start an auction on a given token with a startPrice and duration.
     * @param tokenId   The NFT to auction.
     * @param startPrice The minimum starting bid.
     * @param reservePrice The minimum price to sell the token for.
     * @param minbidincrementPercentage The minimum percentage increase in bid.
     * @param duration   Length of the auction in seconds.
     * @param timeBuffer Duration in seconds between last bid and auction end.
     */
    function startAuction(
        uint256 tokenId,
        uint256 startPrice,
        uint256 reservePrice,
        uint8 minbidincrementPercentage,
        uint256 duration,
        uint256 timeBuffer
    ) external whenNotPaused {
        require(
            pokemonNFT.ownerOf(tokenId) == msg.sender,
            "Not the token owner"
        );
        require(startPrice > 0, "Start price must be > 0");
        require(reservePrice > 0, "Reserve price must be > 0");
        require(
            duration > timeBuffer && duration > 0,
            "Duration must be > 0 and duration must be > timeBuffer"
        );
        require(timeBuffer >= 0, "Time buffer must be >= 0");
        require(
            minbidincrementPercentage > 0,
            "Minimum bid increment percentage must be > 0"
        );

        // Make sure there is no active listing or auction
        require(!listings[tokenId].active, "Token already listed");
        require(!auctions[tokenId].active, "Auction already active");

        // Approve the marketplace
        require(
            pokemonNFT.getApproved(tokenId) == address(this) ||
                pokemonNFT.isApprovedForAll(msg.sender, address(this)),
            "Marketplace not approved"
        );

        auctions[tokenId] = Auction({
            seller: msg.sender,
            startPrice: startPrice,
            reservePrice: reservePrice,
            minbidincrementPercentage: minbidincrementPercentage,
            highestBid: 0,
            highestBidder: address(0),
            endTime: block.timestamp + duration,
            active: true,
            timeBuffer: timeBuffer
        });

        emit AuctionStarted(
            tokenId,
            msg.sender,
            startPrice,
            reservePrice,
            duration
        );
    }

    /**
     * @notice Place a bid on an active auction.
     * @param tokenId The ID of the token to bid on.
     */
    function placeBid(
        uint256 tokenId
    ) external payable whenNotPaused nonReentrant {
        Auction storage auctionItem = auctions[tokenId];
        require(auctionItem.active, "Auction not active");
        require(block.timestamp < auctionItem.endTime, "Auction has ended");
        require(auctionItem.seller != msg.sender, "Seller cannot bid");
        require(
            msg.sender != auctionItem.highestBidder,
            "You already have the highest bid"
        );

        uint256 currentBid = msg.value;
        require(
            currentBid >
                ((auctionItem.highestBid *
                    (100 + auctionItem.minbidincrementPercentage) +
                    99) / 100) &&
                currentBid >= auctionItem.startPrice,
            "Bid not high enough"
        );

        // Refund the previous highest bidder
        if (auctionItem.highestBidder != address(0)) {
            (bool refunded, ) = payable(auctionItem.highestBidder).call{
                value: auctionItem.highestBid
            }("");

            // Do this if refund fails, because if refund fails, entire bid is lost
            if (!refunded) {
                pendingWithdrawals[auctionItem.highestBidder] += auctionItem
                    .highestBid;

                emit RefundFailed(
                    tokenId,
                    auctionItem.highestBidder,
                    auctionItem.highestBid
                );
            }
        }

        // Update auction with new highest bid
        auctionItem.highestBid = currentBid;
        auctionItem.highestBidder = msg.sender;

        if (auctionItem.endTime - block.timestamp < auctionItem.timeBuffer) {
            auctionItem.endTime = block.timestamp + auctionItem.timeBuffer;

            emit AuctionExtended(
                tokenId,
                msg.sender,
                currentBid,
                auctionItem.endTime
            );
        }

        emit BidPlaced(tokenId, msg.sender, currentBid);
    }

    /**
     * @notice End an auction after the time has passed.
     *         Transfers NFT to the highest bidder and funds to the seller.
     * @param tokenId The ID of the token auctioned.
     */
    function endAuction(uint256 tokenId) external whenNotPaused nonReentrant {
        Auction storage auctionItem = auctions[tokenId];
        require(auctionItem.active, "Auction not active");
        require(
            block.timestamp >= auctionItem.endTime,
            "Auction still ongoing"
        );

        // Capture values to prevent reentracy attacks
        address highestBidder = auctionItem.highestBidder;
        uint256 highestBid = auctionItem.highestBid;

        auctionItem.highestBidder = address(0);
        auctionItem.highestBid = 0;

        // Mark auction as ended
        auctionItem.active = false;

        // If there was no bid, do nothing else (NFT remains with seller)
        if (highestBidder == address(0)) {
            emit AuctionFailed(tokenId);
            return;
        }

        // If the highest bid is less than the reserve price, do nothing else
        if (highestBid < auctionItem.reservePrice) {
            // Refund the highest bidder
            (bool refundSent, ) = payable(highestBidder).call{
                value: highestBid
            }("");

            if (!refundSent) {
                pendingWithdrawals[highestBidder] += highestBid;

                emit RefundFailed(tokenId, highestBidder, highestBid);
                return;
            }

            emit AuctionFailed(tokenId);
            return;
        }

        // Transfer NFT from seller to highest bidder
        pokemonNFT.safeTransferFrom(auctionItem.seller, highestBidder, tokenId);

        // Payout the seller
        (bool sent, ) = payable(auctionItem.seller).call{value: highestBid}("");
        require(sent, "Failed to pay seller");

        emit AuctionEnded(tokenId, highestBidder, highestBid);
    }

    /**
     * @notice Withdraw funds if auction has failed
     */
    function withdraw() external nonReentrant {
        uint256 amount = pendingWithdrawals[msg.sender];
        require(amount > 0, "No funds to withdraw");

        pendingWithdrawals[msg.sender] = 0;

        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Withdrawal failed");
    }

    // ------------------------------------------------------------------------
    // Misc
    // ------------------------------------------------------------------------
    function supportsInterface(
        bytes4 interfaceId
    ) public view override(AccessControl) returns (bool) {
        return super.supportsInterface(interfaceId);
    }
}
