Below is an example test suite to help you get started testing your Marketplace (PokemonMarketplace) and NFT (PokemonNFT) contracts using Hardhat in a similar style to the Lock contract tests.

--------------------------------------------------------------------------------
1. Preparation & Dependencies
--------------------------------------------------------------------------------

• Make sure you have the relevant Hardhat plugins installed:
  npm install --save-dev @nomicfoundation/hardhat-toolbox chai

• Your hardhat.config.ts or hardhat.config.js should be set up to compile Solidity >= 0.8.0 and recognize the relevant imports.

--------------------------------------------------------------------------------
2. Example Marketplace Tests (PokemonMarketplace.test.ts)
--------------------------------------------------------------------------------

Below is a “happy path” oriented set of tests to illustrate how you could structure them. You can expand each describe block with more negative/revert scenarios as needed.

Create a file named PokemonMarketplace.test.ts in your test/ folder:

--------------------------------------------------------------------------------
test/PokemonMarketplace.test.ts
--------------------------------------------------------------------------------
import { loadFixture, time } from "@nomicfoundation/hardhat-toolbox-viem/network-helpers";
import { expect } from "chai";
import hre from "hardhat";
import { getAddress } from "viem";

/**
 * This test suite covers the PokemonMarketplace contract.
 * We deploy both PokemonNFT and PokemonMarketplace, then run key scenarios:
 *  - Listing an NFT for a fixed price.
 *  - Purchasing a listed NFT.
 *  - Canceling a listing.
 *  - Starting an auction, bidding, and ending the auction.
 */
describe("PokemonMarketplace", function () {
  async function deployContractsFixture() {
    /**
     * 1. Deploy our NFT contract (PokemonNFT).
     * 2. Deploy the Marketplace contract, passing in the NFT address.
     * 3. Mint an NFT to `owner` so we can list it in the marketplace.
     */
    const [owner, otherAccount, bidder] = await hre.viem.getWalletClients();

    const pokemonNFT = await hre.viem.deployContract("PokemonNFT", ["PokemonCollection", "PKMN"]);

    // Deploy the marketplace by passing the NFT contract address in the constructor
    const marketplace = await hre.viem.deployContract("PokemonMarketplace", [pokemonNFT.address]);

    // We’ll need a public client for reading on-chain data
    const publicClient = await hre.viem.getPublicClient();

    // Mint an NFT to `owner`
    // In PokemonNFT, mintRareCard requires MINTER_ROLE, so first we need to ensure `owner` has that role.
    // By default in the constructor, msg.sender has the MINTER_ROLE. 
    // If that’s the same address that Hardhat uses to deploy, then we’re good to mint.
    const tokenId = 1n;
    const metadata = {
      name: "Pikachu",
      cardType: 1,
      rarity: 2,
      cardDetailURL: "https://example.com/pikachu",
      hp: 50n,
    };
    // NOTE: cardMetadata uses a “uint8 cardType” and “uint256 hp”, so be mindful of conversion to BigInt as needed
    await pokemonNFT.write.mintRareCard([getAddress(owner.account.address), metadata, ""]);

    return { 
      marketplace, 
      pokemonNFT, 
      publicClient, 
      owner, 
      otherAccount, 
      bidder 
    };
  }

  describe("Deployment", function () {
    it("Should set the correct NFT address in the Marketplace", async function () {
      const { marketplace, pokemonNFT } = await loadFixture(deployContractsFixture);

      const nftAddr = await marketplace.read.pokemonNFT();
      expect(nftAddr).to.equal(pokemonNFT.address);
    });
  });

  describe("Listings", function () {
    it("Should allow a user to list their NFT for a fixed price", async function () {
      const { marketplace, pokemonNFT, owner } = await loadFixture(deployContractsFixture);

      // Approve the marketplace for the token before listing
      await pokemonNFT.write.approve([marketplace.address, 1n]);

      // List the NFT
      const price = 10n ** 15n; // 0.001 ETH for example
      await expect(
        marketplace.write.listCard([1n, price])
      ).to.be.fulfilled;

      // Check the listing
      const listing = await marketplace.read.listings([1n]);
      expect(listing.active).to.be.true;
      expect(listing.price).to.equal(price);
      expect(getAddress(listing.seller)).to.equal(getAddress(owner.account.address));
    });

    it("Should allow a buyer to purchase a listed NFT", async function () {
      const { marketplace, pokemonNFT, owner, otherAccount } = await loadFixture(deployContractsFixture);

      // Approve + List
      await pokemonNFT.write.approve([marketplace.address, 1n]);
      const price = 10n ** 15n;
      await marketplace.write.listCard([1n, price]);

      // Connect marketplace contract to the second account
      const marketplaceAsOther = await hre.viem.getContractAt("PokemonMarketplace", marketplace.address, {
        client: { wallet: otherAccount },
      });

      // Buy with otherAccount (they must send enough ETH)
      await expect(
        marketplaceAsOther.write.buyCard([1n], { value: price })
      ).to.be.fulfilled;

      // Verify `otherAccount` is now the owner of the NFT
      const newOwner = await pokemonNFT.read.ownerOf([1n]);
      expect(newOwner).to.equal(getAddress(otherAccount.account.address));

      // The listing should be inactive now
      const listing = await marketplace.read.listings([1n]);
      expect(listing.active).to.be.false;
    });

    it("Should allow the seller to cancel a listing", async function () {
      const { marketplace, pokemonNFT, owner } = await loadFixture(deployContractsFixture);

      // Approve + List
      await pokemonNFT.write.approve([marketplace.address, 1n]);
      const price = 10n ** 15n;
      await marketplace.write.listCard([1n, price]);

      // Cancel the listing
      await expect(
        marketplace.write.cancelListing([1n])
      ).to.be.fulfilled;

      const listing = await marketplace.read.listings([1n]);
      expect(listing.active).to.be.false;
    });
  });

  describe("Auctions", function () {
    it("Should allow a user to start an auction", async function () {
      const { marketplace, pokemonNFT, owner } = await loadFixture(deployContractsFixture);

      // Approve the marketplace for the token
      await pokemonNFT.write.setApprovalForAll([marketplace.address, true]);

      await expect(
        marketplace.write.startAuction([
          1n,       // tokenId
          10n ** 15n, // startPrice
          2n * 10n ** 15n,  // reservePrice
          5,        // minbidincrementPercentage
          3600n,    // duration = 1 hour
          300n,     // timeBuffer = 5min
        ])
      ).to.be.fulfilled;

      const auction = await marketplace.read.auctions([1n]);
      expect(auction.active).to.be.true;
      expect(auction.seller).to.equal(getAddress(owner.account.address));
    });

    it("Should allow others to place a bid", async function () {
      const { marketplace, pokemonNFT, otherAccount } = await loadFixture(deployContractsFixture);

      // Approve + Start Auction
      await pokemonNFT.write.setApprovalForAll([marketplace.address, true]);
      await marketplace.write.startAuction([1n, 10n ** 15n, 2n * 10n ** 15n, 5, 3600n, 300n]);

      // Try bidding from otherAccount
      const marketplaceAsOther = await hre.viem.getContractAt("PokemonMarketplace", marketplace.address, {
        client: { wallet: otherAccount },
      });
      const bidAmount = 15n ** 15n; // 0.015 ETH, must be >= startPrice & >= min increment

      await expect(
        marketplaceAsOther.write.placeBid([1n], { value: bidAmount })
      ).to.be.fulfilled;

      const auction = await marketplace.read.auctions([1n]);
      expect(auction.highestBid).to.equal(bidAmount);
      expect(getAddress(auction.highestBidder)).to.equal(getAddress(otherAccount.account.address));
    });

    it("Should allow the seller to end the auction after time passes", async function () {
      const { marketplace, pokemonNFT, otherAccount, publicClient } = await loadFixture(deployContractsFixture);

      // Approve + Start Auction
      await pokemonNFT.write.setApprovalForAll([marketplace.address, true]);
      await marketplace.write.startAuction([1n, 10n ** 15n, 2n * 10n ** 15n, 5, 100n, 60n]);

      // Place a bid from otherAccount
      const marketplaceAsOther = await hre.viem.getContractAt("PokemonMarketplace", marketplace.address, {
        client: { wallet: otherAccount },
      });
      await marketplaceAsOther.write.placeBid([1n], { value: 2n * 10n ** 15n });

      // Increase time past the end
      const auctionData = await marketplace.read.auctions([1n]);
      const endTime = auctionData.endTime;
      await time.increaseTo(endTime + 10n);

      // End auction from default signer (seller)
      await expect(
        marketplace.write.endAuction([1n])
      ).to.be.fulfilled;

      // Check that the auction is no longer active
      const auctionEnded = await marketplace.read.auctions([1n]);
      expect(auctionEnded.active).to.be.false;

      // The NFT should be owned by `otherAccount`
      const ownerOfToken = await pokemonNFT.read.ownerOf([1n]);
      expect(ownerOfToken).to.equal(getAddress(otherAccount.account.address));
    });
  });
});

